div.p:
Every ownership transfer must be documented:
c
// Ownership transfer: caller now owns 'result'
char* result = expand_something(input);

For complex structures, provide cleanup:
c
void expand_result_free(ExpandResult* r);
void ast_free(ASTNode* node);

char* output = capture_command_output(cmd);
// ... use output ...
free(output);  // MUST free!

// field_split modifies 'str' in place
char** fields = field_split(str, ifs, &count);
// fields[] point INTO str
free(str);  // DON'T do this until done with fields!

while ((entry = readdir(dir))) {
matches[count++] = strdup(entry->d_name);
// Each match must be freed individually
}

typedef struct {
char* data;      // malloc'd
size_t len;
size_t capacity;
} CaptureBuffer;

char** fields;
int num_fields = field_split(working, ifs, &fields)
free(working)

typedef struct {
char** words;    // Array of strings
int count;
int capacity;
} ExpandResult;

for (i = 0; i < result.count; i++) {
char* unquoted = remove_quotes(result.words[i])
free(result.words[i])
result.words[i] = unquoted
}

ExpandResult result = {
.words = {
[0] → "final_word_1"  // owned
[1] → "final_word_2"  // owned
[2] → NULL
},
.count = 2,
.capacity = 16
}

void expand_result_free(ExpandResult* r) {
for (int i = 0; i < r->count; i++) {
free(r->words[i]);  // Free each word
}
free(r->words);       // Free array
}
